import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

type RingType = 'VERY_SMALL' | 'SMALL' | 'MEDIUM';

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        
  endP?: number;    
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; 
  totalTicksInRange: number; 
