    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && !obj.hit && !obj.missed && obj.graphic) {
        const pos = this.getPathPosition(obj.p);
        const ringRadius = this.getRingRadius(obj.ringType);
        const ringColor = this.getRingColor(obj.ringType);

        obj.graphic.setPosition(pos.x, pos.y).setRadius(ringRadius * this.uiScale);
        obj.graphic.setStrokeStyle(3, ringColor);
        obj.graphic.setFillStyle(ringColor, 0.3);

        if (obj.nailHead) {
            obj.nailHead.setPosition(pos.x, pos.y).setDisplaySize(ringRadius * 2 * this.uiScale, ringRadius * 2 * this.uiScale);
        }
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.isTransitioning || this.worldPoints.length < 2) return;

    const acceleration = 1 + (this.cursorProgress * 0.5);
    let currentTickSpeed = this.cursorSpeed * acceleration;

    const activeTap = this.interactables.find(obj => 
        obj.type === 'TAP' && !obj.hit && !obj.missed && 
        Math.abs(this.cursorProgress - obj.p) < 0.05
    );
    if (activeTap) {
        currentTickSpeed *= this.getRingSpeedMultiplier(activeTap.ringType);
    }

    this.cursorProgress += currentTickSpeed * delta;

    this.interactables.forEach((obj) => { if (!obj.hit && !obj.missed) { if (this.cursorProgress > (obj.endP ?? obj.p) + 0.1) { if (obj.type === 'TAP') { obj.missed = true; const pos = this.getPathPosition(obj.p); this.handleMiss(pos.x, pos.y, obj); } else if (obj.type === 'DRAG' && !obj.startHit && !obj.missedStart) obj.missedStart = true; } } });
    this.handleDragLogic(time, delta); if (this.cursorProgress >= 1.0) this.finishPhase();
    const pos = this.getPathPosition(this.cursorProgress); this.cursor.setPosition(pos.x, pos.y);
    const rotationOffset = (!this.isLeatherWork && (this.currentPhase === 2 || this.currentPhase === 4)) ? 0 : -Math.PI / 2;
    this.cursor.angle += Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(pos.angle + rotationOffset)) * 0.15;
    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        if (p >= obj.p && p <= obj.endP!) {
            obj.totalTicksInRange += delta; const pointer = this.input.activePointer;
            if (pointer.isDown && Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y) < 60 * this.uiScale) {
                if (!obj.startHit) { obj.startHit = true; if (!obj.tracedSegments) obj.tracedSegments = []; obj.tracedSegments.push({ start: p, end: p }); }
                obj.dragSuccessTicks += delta; this.dragPenaltyTimer = 0; if (this.cursorSprite.visible) this.cursorSprite.setTint(0xfbbf24); if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfcd34d);
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                const lastSeg = obj.tracedSegments![obj.tracedSegments!.length - 1]; if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) lastSeg.end = p; else obj.tracedSegments!.push({ start: p, end: p });
            } else if (obj.startHit) {
                this.dragPenaltyTimer += delta; if (this.dragPenaltyTimer > 150) { 
                    this.dragPenaltyTimer = 0; 
                    this.currentQuality = Math.max(0, this.currentQuality - 1.2); 
                    if (this.combo > 0) {
                        this.combo = 0;
                        this.syncFutureRingsToCombo();
                    }
                    this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.001); 
                }
            }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.92 && obj.startHitPerfect && !obj.missedStart) { 
                obj.hit = true; 
                this.currentQuality = Math.min(120, this.currentQuality + 1.0); 
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); 
                this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15); 
            }
            else if (ratio > 0.60) { 
                obj.hit = true; 
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y); 
            }
            else { obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y); }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) { this.cursorSprite.clearTint(); if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfbbf24); }
  }

  private handleTapHit(idx: number, targetX: number, targetY: number) {
    const obj = this.interactables[idx]; const diff = Math.abs(this.cursorProgress - obj.p); const pos = this.getPathPosition(obj.p);
    if (diff < 0.07) {
      obj.hit = true; const isPerfect = diff < 0.03; const ringColor = this.getRingColor(obj.ringType);
      if (!this.isLeatherWork) { this.hammerSprite.setAlpha(1).setPosition(targetX + 40, targetY - 120).setAngle(5); this.tweens.add({ targets: this.hammerSprite, x: targetX, y: targetY + 20, angle: -30, duration: 100, ease: 'Cubic.in', onComplete: () => { this.tweens.add({ targets: this.hammerSprite, angle: -10, y: targetY + 10, alpha: 0, duration: 250, ease: 'Cubic.out' }); } }); }
      if (obj.nailHead) this.tweens.add({ targets: obj.nailHead, displayWidth: obj.nailHead.displayWidth * 0.8, displayHeight: obj.nailHead.displayHeight * 0.8, duration: 100, ease: 'Back.easeOut' });

      if (isPerfect) { 
          this.combo++; 
          this.currentQuality = Math.min(120, this.currentQuality + 1.0); 
          this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y); 
          this.createSparks(pos.x, pos.y, 0xfbbf24, 15); 
          if (this.combo >= 8) this.handleEnhancement(pos.x, pos.y); 

          this.syncFutureRingsToCombo();
      }
      else { 
          this.combo = 0; 
          this.showFeedback('GOOD', ringColor, pos.x, pos.y); 
          this.createSparks(pos.x, pos.y, ringColor, 8); 

          this.syncFutureRingsToCombo();
      }

      if (obj.graphic) { 
          const target = obj.graphic; 
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() }); 
      }
    }
  }

  private handleEnhancement(x: number, y: number) { this.enhancementCount++; const pinnedText = this.add.text(x, y, '+1', { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: '#fbbf24', fontStyle: 'bold', stroke: '#000', strokeThickness: 6, shadow: { color: '#000', fill: true, blur: 10 } }).setOrigin(0.5).setDepth(15).setAlpha(0).setScale(0.5); this.root.add(pinnedText); this.tweens.add({ targets: pinnedText, alpha: 1, scale: 1, y: y - 20, duration: 400, ease: 'Back.out' }); }

  private handleMiss(x: number, y: number, obj?: Interactable) { 
      this.combo = 0; 
      this.syncFutureRingsToCombo();
      this.currentQuality = Math.max(0, this.currentQuality - 6); 
      this.showFeedback('MISS', 0xef4444, x, y); 
      this.createSparks(x, y, 0xef4444, 8); 
      this.cameras.main.shake(120, 0.005); 
      if (obj?.graphic) this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => this.destroyTapGraphics(obj) }); 
  }

  private finishPhase() {
    this.isTransitioning = true; this.confirmedProgress = Math.min(100, this.confirmedProgress + 50); this.updateProgressBar();
    this.interactables.forEach(obj => { if (obj.graphic) this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 400 }); if (obj.nailHead) this.tweens.add({ targets: obj.nailHead, alpha: 0, duration: 400 }); });
    const isLastPhase = this.currentPhase >= 2;

    if (isLastPhase) {
        this.win();
    } else {
        this.time.delayedCall(400, () => {
            this.startPhase(this.currentPhase + 1);
        });
    }
  }

  private updateProgressBar() { this.progressBar.width = Math.max(0.1, (this.confirmedProgress / 100) * this.progBg.width); }

  private createSparks(x: number, y: number, color: number, count: number = 12) { const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 }); this.root.add(emitter); emitter.explode(count); this.time.delayedCall(600, () => emitter.destroy()); }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string { if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE'; }
  private getLabelColor(q: number): string { if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444'; }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => { this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality, this.enhancementCount); }); } });
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import { User, ChevronRight, Coins, Package, Lock } from 'lucide-react';
import { useGame } from '../context/GameContext';
import { materials } from '../data/materials';
import { getAssetUrl } from '../utils';

interface DialogueOption {
  label: string;
  action: () => void;
  variant?: 'primary' | 'danger' | 'neutral';
  disabled?: boolean;
}

interface ItemDetail {
  id: string;
  image?: string; 
  icon: string;
  price: number;
  requirements?: { id: string; count: number }[];
  isUnlocked?: boolean;
}

interface DialogueBoxProps {
  speaker: string;
  text: string;
  options?: DialogueOption[];
  highlightTerm?: string;
  itemDetail?: ItemDetail;
  className?: string;
  speakerAvatar?: string;
}

const DialogueBox: React.FC<DialogueBoxProps> = ({ 
  speaker, 
  text, 
  options = [], 
  highlightTerm,
  itemDetail,
  className = "relative w-full z-40",
  speakerAvatar
}) => {
  const { state } = useGame();
  const [displayedIndex, setDisplayedIndex] = useState(0);
  const [isTyping, setIsTyping] = useState(false);
  const [showItemTooltip, setShowItemTooltip] = useState(false);
  const [tooltipCoords, setTooltipCoords] = useState({ x: 0, y: 0 });
  const [imgError, setImgError] = useState(false);

  const isMounted = useRef(true);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const textContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    isMounted.current = true;
    return () => { 
      isMounted.current = false;
      if (timerRef.current) clearInterval(timerRef.current);
      // 언마운트 시 툴팁 강제 종료
      setShowItemTooltip(false);
    };
  }, []);

  // 전역 클릭 감지: 툴팁이 열려있을 때 화면 어디든 클릭하면 닫힘
  useEffect(() => {
    if (!showItemTooltip) return;
    const handleGlobalClick = () => setShowItemTooltip(false);
    // 마우스 다운 시점에 즉시 반응하여 탭 이동 시에도 툴팁이 먼저 닫히게 함
    window.addEventListener('mousedown', handleGlobalClick);
    return () => window.removeEventListener('mousedown', handleGlobalClick);
  }, [showItemTooltip]);

  useEffect(() => {
    if (textContainerRef.current) {
      const container = textContainerRef.current;
      const scrollHandle = requestAnimationFrame(() => {
        container.scrollTop = container.scrollHeight;
      });
      return () => cancelAnimationFrame(scrollHandle);
    }
  }, [displayedIndex, text, isTyping]);

  useEffect(() => {
    if (timerRef.current) clearInterval(timerRef.current);

    setDisplayedIndex(0);
    setIsTyping(true);
    setShowItemTooltip(false);
    setImgError(false);
    let index = 0;
    const speed = 25; 

    timerRef.current = setInterval(() => {
      if (!isMounted.current) return;

      index++;
      if (index > text.length) {
        if (timerRef.current) clearInterval(timerRef.current);
        setIsTyping(false);
        setDisplayedIndex(text.length);
      } else {
        setDisplayedIndex(index);
      }
    }, speed);

    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [text]);

  const playClickSfx = () => {
      window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'item_click.mp3' } }));
  };

  const handleSkipTyping = () => {
    if (isTyping) {
      if (timerRef.current) clearInterval(timerRef.current);
      setDisplayedIndex(text.length);
      setIsTyping(false);
      playClickSfx();
    }
  };

  const getInventoryCount = (id: string) => {
    return state.inventory.find(i => i.id === id)?.quantity || 0;
  };

  const updateTooltipPosition = (e: React.MouseEvent | React.TouchEvent) => {
    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    setTooltipCoords({
      x: rect.left + rect.width / 2,
      y: rect.top
    });
  };

  const renderFormattedText = () => {
    if (!highlightTerm) {
      return <span>{text.slice(0, displayedIndex)}</span>;
    }

    const parts = text.split(new RegExp(`(${highlightTerm})`, 'g'));
    let charCount = 0;

    return parts.map((part, i) => {
      const startChar = charCount;
      const endChar = charCount + part.length;
      charCount = endChar;

      const visibleCountInPart = Math.max(0, Math.min(part.length, displayedIndex - startChar));
      if (visibleCountInPart <= 0) return null;

      const visiblePart = part.slice(0, visibleCountInPart);

      if (part === highlightTerm) {
        return (
          <span 
            key={i} 
            className="text-amber-400 font-black underline decoration-amber-500/50 underline-offset-4 cursor-pointer relative inline-block pointer-events-auto"
            onClick={(e) => { 
                e.stopPropagation(); 
                updateTooltipPosition(e); 
                setShowItemTooltip(!showItemTooltip); 
                playClickSfx();
            }}
          >
            {visiblePart}
          </span>
        );
      }

      return <React.Fragment key={i}>{visiblePart}</React.Fragment>;
    });
  };

  const tooltipElement = showItemTooltip && itemDetail && createPortal(
    <div 
      className="fixed z-[10000] pointer-events-none p-3 md:p-4 bg-stone-900/98 backdrop-blur-2xl border-2 border-stone-700 rounded-2xl shadow-[0_20px_50px_rgba(0,0,0,0.9)] w-[80vw] max-w-[240px] md:max-w-[320px] animate-in fade-in zoom-in-95 duration-200"
      style={{ 
        left: `${Math.max(130, Math.min(window.innerWidth - 130, tooltipCoords.x))}px`, 
        top: `${tooltipCoords.y - 10}px`,
        transform: 'translate(-50%, -100%)'
      }}
      onClick={(e) => e.stopPropagation()} // 툴팁 영역 클릭 시에는 닫히지 않게 보호
    >
      <div className="flex items-center gap-3 mb-2 md:mb-3 pb-2 md:pb-3 border-b border-white/10">
        <div className={`w-10 h-10 md:w-16 md:h-16 bg-stone-950 rounded-xl border-2 flex items-center justify-center shadow-inner shrink-0 overflow-hidden ${!itemDetail.isUnlocked ? 'border-amber-600/50' : 'border-stone-800'}`}>
          {!itemDetail.isUnlocked ? (
            <span className="text-2xl md:text-4xl font-serif text-amber-500 font-black animate-pulse">?</span>
          ) : (
            <>
              {!imgError ? (
                <img 
                  src={getAssetUrl(itemDetail.image || `${itemDetail.id}.png`, 'equipments')} 
                  onError={(e) => {
                    console.error('[Tooltip Debug] Image Failed to Load:', (e.target as HTMLImageElement).src);
                    setImgError(true);
                  }}
                  className="w-7 h-7 md:w-11 md:h-11 object-contain" 
                  alt="item" 
                />
              ) : (
                <span className="text-xl md:text-3xl">{itemDetail.icon}</span>
              )}
            </>
          )}
        </div>
        <div className="flex flex-col leading-none">
          <span className="text-[7px] md:text-[10px] text-stone-500 font-black uppercase tracking-widest mb-1">Price</span>
          <div className={`flex items-center gap-1 font-mono font-black text-xs md:text-xl ${!itemDetail.isUnlocked ? 'text-stone-600' : 'text-emerald-400'}`}>
            <Coins className="w-3 h-3 md:w-5 md:h-5" />
            {!itemDetail.isUnlocked ? '???,???' : itemDetail.price.toLocaleString()} G
          </div>
        </div>
      </div>

      <div className="space-y-2">
        <h5 className="text-[7px] md:text-[9px] font-black text-stone-500 uppercase tracking-widest flex items-center gap-1.5">
          <Package className="w-2 h-2 md:w-3 md:h-3" /> Required Materials
        </h5>

        <div className="grid gap-1">
          {itemDetail.requirements && itemDetail.requirements.length > 0 ? (
            itemDetail.requirements.map((req, idx) => {
              const isClue = idx === 0; 
              const shouldShow = itemDetail.isUnlocked || isClue;

              if (!shouldShow) {
                return (
                  <div key={req.id} className="flex justify-between items-center text-[8px] md:text-xs opacity-40">
                    <span className="truncate mr-2 font-bold tracking-tight text-stone-600">
                      ???
                    </span>
                    <div className="flex items-center gap-1 shrink-0">
                      <span className="font-mono font-black text-stone-700">
                        ? / ?
                      </span>
                      <div className="w-1 h-1 rounded-full bg-stone-800" />
                    </div>
                  </div>
                );
              }

              const hasCount = getInventoryCount(req.id);
              const isEnough = hasCount >= req.count;
              const mat = Object.values(materials).find(m => m.id === req.id);

              return (
                <div key={req.id} className="flex justify-between items-center text-[8px] md:text-xs">
                  <span className={`truncate mr-2 font-bold tracking-tight ${isEnough ? 'text-stone-300' : 'text-red-400'}`}>
                    {mat?.name || req.id}
                  </span>
                  <div className="flex items-center gap-1 shrink-0">
                    <span className={`font-mono font-black ${isEnough ? 'text-stone-500' : 'text-red-500'}`}>
                      {hasCount}/{req.count}
                    </span>
                    <div className={`w-1 h-1 rounded-full ${isEnough ? 'bg-emerald-500 shadow-[0_0_4px_rgba(16,185,129,0.5)]' : 'bg-red-500 animate-pulse'}`} />
                  </div>
                </div>
              );
            })
          ) : (
            <div className="text-[8px] md:text-xs text-stone-600 italic">No specific requirements found.</div>
          )}
        </div>

        {!itemDetail.isUnlocked && (
          <div className="mt-2 pt-2 border-t border-white/5 flex flex-col items-center text-center">
            <div className="flex items-center gap-1.5 text-amber-600/80">
              <Lock className="w-2.5 h-2.5 md:w-3 md:h-3" />
              <span className="text-[6px] md:text-[8px] font-black uppercase tracking-widest">Locked Knowledge</span>
            </div>
          </div>
        )}
      </div>

      <div className="absolute top-full left-1/2 -translate-x-1/2 w-0 h-0 border-l-[8px] md:border-l-[12px] border-l-transparent border-r-[8px] md:border-r-[12px] border-r-transparent border-t-[8px] md:border-t-[12px] border-t-stone-900/98"></div>
    </div>,
    document.body
  );

  return (
    <div className={className} onClick={(e) => { if (showItemTooltip) { e.stopPropagation(); setShowItemTooltip(false); playClickSfx(); } }}>
      {tooltipElement}

      <div 
        className="w-full h-[22dvh] min-h-[120px] md:h-[28vh] md:min-h-[160px] bg-stone-950/25 backdrop-blur-3xl border border-white/10 md:border-2 rounded-2xl md:rounded-3xl shadow-[0_25px_70px_rgba(0,0,0,0.7)] flex flex-row overflow-hidden animate-in slide-in-from-bottom-8 fade-in duration-500 ring-1 ring-white/10"
      >
        <div className="bg-stone-900/20 p-2 md:p-6 border-r border-white/5 flex flex-col items-center gap-1 md:gap-4 w-20 md:w-48 shrink-0 justify-center">
          <div className="w-9 h-9 md:w-20 md:h-20 rounded-full bg-gradient-to-br from-amber-900/30 to-stone-800/40 border border-amber-600/30 flex items-center justify-center shadow-inner ring-1 ring-white/5 overflow-hidden">
             {speakerAvatar ? (
               <img src={speakerAvatar} className="w-full h-full object-cover" alt={speaker} />
             ) : (
               <User className="w-5 h-5 md:w-10 md:h-10 text-amber-500/90 drop-shadow-[0_0_15px_rgba(245,158,11,0.5)]" />
             )}
          </div>
          <div className="flex flex-col items-center overflow-hidden w-full">
              <span className="font-black text-amber-50 text-[10px] md:text-xl text-center font-serif leading-tight tracking-tight drop-shadow-md truncate w-full px-1">
                {speaker}
              </span>
          </div>
        </div>

        <div 
          className="flex-1 p-2.5 md:p-8 relative flex flex-col min-h-0 bg-gradient-to-br from-white/5 to-transparent cursor-pointer"
          onClick={handleSkipTyping}
        >
          <div 
            ref={textContainerRef}
            className={`flex-1 overflow-y-auto overflow-x-hidden custom-scrollbar pr-1 md:pr-2 mb-1 md:mb-2 min-h-0 ${isTyping ? 'typing-active' : ''}`}
            style={{ scrollBehavior: isTyping ? 'auto' : 'smooth' }}
          >
            <div 
              className="text-stone-50 leading-snug md:leading-relaxed font-medium drop-shadow-[0_2px_4px_rgba(0,0,0,0.5)] transition-opacity duration-300 break-words whitespace-pre-wrap"
              style={{ fontSize: 'clamp(0.9rem, 2.4dvh, 1.6rem)' }}
            >
              {renderFormattedText()}
            </div>
          </div>

          {!isTyping && options.length > 0 && (
            <div className="mt-auto pt-2 flex flex-wrap gap-1.5 md:gap-4 justify-end animate-in fade-in slide-in-from-right-4 pb-1 shrink-0">
              {options.map((option, idx) => (
                <button
                  key={idx}
                  onClick={(e) => { e.stopPropagation(); playClickSfx(); option.action(); }}
                  disabled={option.disabled}
                  className={`px-4 md:px-10 py-1.5 md:py-4 rounded-lg md:rounded-xl font-black text-[9px] md:text-sm flex items-center gap-1.5 md:gap-3 transition-all transform active:scale-95 border shadow-2xl ${
                    option.disabled 
                      ? 'bg-stone-800/40 text-stone-600 border-stone-700/30 cursor-not-allowed'
                      : option.variant === 'danger'
                        ? 'bg-red-900/60 text-red-50 border-red-800/50 hover:bg-red-700 hover:border-red-400'
                        : option.variant === 'neutral'
                            ? 'bg-stone-800/60 text-stone-100 border-stone-600 hover:bg-stone-750 hover:border-stone-400'
                            : 'bg-amber-700/80 text-white border-amber-500 hover:bg-amber-600 hover:border-amber-300 hover:shadow-amber-900/60'
                  }`}
                >
                  <span className="whitespace-nowrap">{option.label}</span>
                  {!option.disabled && <ChevronRight className="hidden xs:block w-2.5 md:w-5 h-2.5 md:h-5 opacity-70 group-hover:translate-x-1 transition-transform" />}
                </button>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

