import { materials } from '../data/materials';
import { getAssetUrl } from '../utils';

interface DialogueOption {
  label: string;
  action: () => void;
  variant?: 'primary' | 'danger' | 'neutral';
  disabled?: boolean;
}

interface ItemDetail {
  id: string;
  image?: string; 
  icon: string;
  price: number;
  requirements?: { id: string; count: number }[];
  isUnlocked?: boolean;
}

interface DialogueBoxProps {
  speaker: string;
  text: string;
  options?: DialogueOption[];
  highlightTerm?: string;
  itemDetail?: ItemDetail;
  className?: string;
  speakerAvatar?: string;
}

const DialogueBox: React.FC<DialogueBoxProps> = ({ 
  speaker, 
  text, 
  options = [], 
  highlightTerm,
  itemDetail,
  className = "relative w-full z-40",
  speakerAvatar
}) => {
  const { state } = useGame();
  const [displayedIndex, setDisplayedIndex] = useState(0);
  const [isTyping, setIsTyping] = useState(false);
  const [showItemTooltip, setShowItemTooltip] = useState(false);
  const [tooltipCoords, setTooltipCoords] = useState({ x: 0, y: 0 });
  const [imgError, setImgError] = useState(false);

  const isMounted = useRef(true);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const textContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    isMounted.current = true;
    return () => { 
      isMounted.current = false;
      if (timerRef.current) clearInterval(timerRef.current);
      // 언마운트 시 툴팁 강제 종료 (탭 전환 시 대응)
      setShowItemTooltip(false);
    };
  }, []);

  // 전역 클릭 감지: 툴팁이 열려있을 때 화면 어디든 클릭하면 닫힘
  useEffect(() => {
    if (!showItemTooltip) return;
    const handleGlobalClick = () => setShowItemTooltip(false);
    window.addEventListener('mousedown', handleGlobalClick);
    window.addEventListener('touchstart', handleGlobalClick);
    return () => {
      window.removeEventListener('mousedown', handleGlobalClick);
      window.removeEventListener('touchstart', handleGlobalClick);
    };
  }, [showItemTooltip]);

  useEffect(() => {
    if (textContainerRef.current) {
      const container = textContainerRef.current;
      const scrollHandle = requestAnimationFrame(() => {
        container.scrollTop = container.scrollHeight;
      });
      return () => cancelAnimationFrame(scrollHandle);
    }
  }, [displayedIndex, text, isTyping]);

  useEffect(() => {
    if (timerRef.current) clearInterval(timerRef.current);

    setDisplayedIndex(0);
    setIsTyping(true);
    setShowItemTooltip(false);
    setImgError(false);
    let index = 0;
    const speed = 25; 

    timerRef.current = setInterval(() => {
      if (!isMounted.current) return;

      index++;
      if (index > text.length) {
        if (timerRef.current) clearInterval(timerRef.current);
        setIsTyping(false);
        setDisplayedIndex(text.length);
      } else {
        setDisplayedIndex(index);
      }
    }, speed);

    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [text]);

  const playClickSfx = () => {
      window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'item_click.mp3' } }));
  };

  const handleSkipTyping = () => {
    if (isTyping) {
      if (timerRef.current) clearInterval(timerRef.current);
      setDisplayedIndex(text.length);
      setIsTyping(false);
      playClickSfx();
    }
  };

  const getInventoryCount = (id: string) => {
    return state.inventory.find(i => i.id === id)?.quantity || 0;
  };

  const updateTooltipPosition = (e: React.MouseEvent | React.TouchEvent) => {
    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    setTooltipCoords({
      x: rect.left + rect.width / 2,
      y: rect.top
    });
  };

  const renderFormattedText = () => {
    if (!highlightTerm) {
      return <span>{text.slice(0, displayedIndex)}</span>;
    }

    const parts = text.split(new RegExp(`(${highlightTerm})`, 'g'));
    let charCount = 0;

    return parts.map((part, i) => {
      const startChar = charCount;
      const endChar = charCount + part.length;
      charCount = endChar;

      const visibleCountInPart = Math.max(0, Math.min(part.length, displayedIndex - startChar));
      if (visibleCountInPart <= 0) return null;

      const visiblePart = part.slice(0, visibleCountInPart);

      if (part === highlightTerm) {
        return (
          <span 
            key={i} 
            className="text-amber-400 font-black underline decoration-amber-500/50 underline-offset-4 cursor-pointer relative inline-block pointer-events-auto"
            onClick={(e) => { 
                e.stopPropagation(); 
                updateTooltipPosition(e); 
                setShowItemTooltip(!showItemTooltip); 
                playClickSfx();
            }}
          >
            {visiblePart}
          </span>
        );
      }

      return <React.Fragment key={i}>{visiblePart}</React.Fragment>;
    });
  };

  const tooltipElement = showItemTooltip && itemDetail && createPortal(
    <div 
      className="fixed z-[10000] pointer-events-auto p-3 md:p-4 bg-stone-900/98 backdrop-blur-2xl border-2 border-stone-700 rounded-2xl shadow-[0_20px_50px_rgba(0,0,0,0.9)] w-[80vw] max-w-[240px] md:max-w-[320px] animate-in fade-in zoom-in-95 duration-200 cursor-pointer"
      style={{ 
        left: `${Math.max(130, Math.min(window.innerWidth - 130, tooltipCoords.x))}px`, 
        top: `${tooltipCoords.y - 10}px`,
        transform: 'translate(-50%, -100%)'
      }}
      onClick={(e) => {
        e.stopPropagation();
        setShowItemTooltip(false);
        playClickSfx();
      }}
    >
      <div className="flex items-center gap-3 mb-2 md:mb-3 pb-2 md:pb-3 border-b border-white/10">
        <div className={`w-10 h-10 md:w-16 md:h-16 bg-stone-950 rounded-xl border-2 flex items-center justify-center shadow-inner shrink-0 overflow-hidden ${!itemDetail.isUnlocked ? 'border-amber-600/50' : 'border-stone-800'}`}>
          {!itemDetail.isUnlocked ? (
            <span className="text-2xl md:text-4xl font-serif text-amber-500 font-black animate-pulse">?</span>
          ) : (
            <>
              {!imgError ? (
                <img 
                  src={getAssetUrl(itemDetail.image || `${itemDetail.id}.png`, 'equipments')} 
                  onError={(e) => {
                    console.error('[Tooltip Debug] Image Failed to Load:', (e.target as HTMLImageElement).src);
                    setImgError(true);
                  }}
                  className="w-7 h-7 md:w-11 md:h-11 object-contain" 
                  alt="item" 
                />
              ) : (
                <span className="text-xl md:text-3xl">{itemDetail.icon}</span>
              )}
            </>
          )}
        </div>
        <div className="flex flex-col leading-none">
          <span className="text-[7px] md:text-[10px] text-stone-500 font-black uppercase tracking-widest mb-1">Price</span>
          <div className={`flex items-center gap-1 font-mono font-black text-xs md:text-xl ${!itemDetail.isUnlocked ? 'text-stone-600' : 'text-emerald-400'}`}>
            <Coins className="w-3 h-3 md:w-5 md:h-5" />
            {!itemDetail.isUnlocked ? '???,???' : itemDetail.price.toLocaleString()} G
          </div>
        </div>
      </div>

      <div className="space-y-2">
        <h5 className="text-[7px] md:text-[9px] font-black text-stone-500 uppercase tracking-widest flex items-center gap-1.5">
          <Package className="w-2 h-2 md:w-3 md:h-3" /> Required Materials
        </h5>

        <div className="grid gap-1">
          {itemDetail.requirements && itemDetail.requirements.length > 0 ? (
            itemDetail.requirements.map((req, idx) => {
              const isClue = idx === 0; 
              const shouldShow = itemDetail.isUnlocked || isClue;

              if (!shouldShow) {
                return (
                  <div key={req.id} className="flex justify-between items-center text-[8px] md:text-xs opacity-40">
                    <span className="truncate mr-2 font-bold tracking-tight text-stone-600">
                      ???
                    </span>
                    <div className="flex items-center gap-1 shrink-0">
                      <span className="font-mono font-black text-stone-700">
                        ? / ?
                      </span>
                      <div className="w-1 h-1 rounded-full bg-stone-800" />
                    </div>
                  </div>
                );
              }

              const hasCount = getInventoryCount(req.id);
              const isEnough = hasCount >= req.count;
              const mat = Object.values(materials).find(m => m.id === req.id);

              return (
                <div key={req.id} className="flex justify-between items-center text-[8px] md:text-xs">
                  <span className={`truncate mr-2 font-bold tracking-tight ${isEnough ? 'text-stone-300' : 'text-red-400'}`}>
                    {mat?.name || req.id}
                  </span>
                  <div className="flex items-center gap-1 shrink-0">
                    <span className={`font-mono font-black ${isEnough ? 'text-stone-500' : 'text-red-500'}`}>
                      {hasCount}/{req.count}
                    </span>
                    <div className={`w-1 h-1 rounded-full ${isEnough ? 'bg-emerald-500 shadow-[0_0_4px_rgba(16,185,129,0.5)]' : 'bg-red-500 animate-pulse'}`} />
                  </div>
                </div>
              );
            })
          ) : (
            <div className="text-[8px] md:text-xs text-stone-600 italic">No specific requirements found.</div>
          )}
        </div>

        {!itemDetail.isUnlocked && (
          <div className="mt-2 pt-2 border-t border-white/5 flex flex-col items-center text-center">
            <div className="flex items-center gap-1.5 text-amber-600/80">
              <Lock className="w-2.5 h-2.5 md:w-3 md:h-3" />
              <span className="text-[6px] md:text-[8px] font-black uppercase tracking-widest">Locked Knowledge</span>
            </div>
          </div>
        )}
      </div>

      <div className="absolute top-full left-1/2 -translate-x-1/2 w-0 h-0 border-l-[8px] md:border-l-[12px] border-l-transparent border-r-[8px] md:border-r-[12px] border-r-transparent border-t-[8px] md:border-t-[12px] border-t-stone-900/98"></div>
    </div>,
    document.body
  );

  return (
    <div className={className} onClick={(e) => { if (showItemTooltip) { e.stopPropagation(); setShowItemTooltip(false); playClickSfx(); } }}>
      {tooltipElement}

      <div 
        className="w-full h-[22dvh] min-h-[120px] md:h-[28vh] md:min-h-[160px] bg-stone-950/25 backdrop-blur-3xl border border-white/10 md:border-2 rounded-2xl md:rounded-3xl shadow-[0_25px_70px_rgba(0,0,0,0.7)] flex flex-row overflow-hidden animate-in slide-in-from-bottom-8 fade-in duration-500 ring-1 ring-white/10"
      >
        <div className="bg-stone-900/20 p-2 md:p-6 border-r border-white/5 flex flex-col items-center gap-1 md:gap-4 w-20 md:w-48 shrink-0 justify-center">
          <div className="w-9 h-9 md:w-20 md:h-20 rounded-full bg-gradient-to-br from-amber-900/30 to-stone-800/40 border border-amber-600/30 flex items-center justify-center shadow-inner ring-1 ring-white/5 overflow-hidden">
             {speakerAvatar ? (
               <img src={speakerAvatar} className="w-full h-full object-cover" alt={speaker} />
             ) : (
               <User className="w-5 h-5 md:w-10 md:h-10 text-amber-500/90 drop-shadow-[0_0_15px_rgba(245,158,11,0.5)]" />
             )}
          </div>
          <div className="flex flex-col items-center overflow-hidden w-full">
              <span className="font-black text-amber-50 text-[10px] md:text-xl text-center font-serif leading-tight tracking-tight drop-shadow-md truncate w-full px-1">
                {speaker}
              </span>
          </div>
        </div>

        <div 
          className="flex-1 p-2.5 md:p-8 relative flex flex-col min-h-0 bg-gradient-to-br from-white/5 to-transparent cursor-pointer"
          onClick={handleSkipTyping}
        >
          <div 
            ref={textContainerRef}
            className={`flex-1 overflow-y-auto overflow-x-hidden custom-scrollbar pr-1 md:pr-2 mb-1 md:mb-2 min-h-0 ${isTyping ? 'typing-active' : ''}`}
            style={{ scrollBehavior: isTyping ? 'auto' : 'smooth' }}
          >
            <div 
              className="text-stone-50 leading-snug md:leading-relaxed font-medium drop-shadow-[0_2px_4px_rgba(0,0,0,0.5)] transition-opacity duration-300 break-words whitespace-pre-wrap"
              style={{ fontSize: 'clamp(0.9rem, 2.4dvh, 1.6rem)' }}
            >
              {renderFormattedText()}
            </div>
          </div>

          {!isTyping && options.length > 0 && (
            <div className="mt-auto pt-2 flex flex-wrap gap-1.5 md:gap-4 justify-end animate-in fade-in slide-in-from-right-4 pb-1 shrink-0">
              {options.map((option, idx) => (
                <button
                  key={idx}
                  onClick={(e) => { e.stopPropagation(); playClickSfx(); option.action(); }}
                  disabled={option.disabled}
                  className={`px-4 md:px-10 py-1.5 md:py-4 rounded-lg md:rounded-xl font-black text-[9px] md:text-sm flex items-center gap-1.5 md:gap-3 transition-all transform active:scale-95 border shadow-2xl ${
                    option.disabled 
                      ? 'bg-stone-800/40 text-stone-600 border-stone-700/30 cursor-not-allowed'
                      : option.variant === 'danger'
                        ? 'bg-red-900/60 text-red-50 border-red-800/50 hover:bg-red-700 hover:border-red-400'
                        : option.variant === 'neutral'
                            ? 'bg-stone-800/60 text-stone-100 border-stone-600 hover:bg-stone-750 hover:border-stone-400'
                            : 'bg-amber-700/80 text-white border-amber-500 hover:bg-amber-600 hover:border-amber-300 hover:shadow-amber-900/60'
                  }`}
                >
                  <span className="whitespace-nowrap">{option.label}</span>
                  {!option.disabled && <ChevronRight className="hidden xs:block w-2.5 md:w-5 h-2.5 md:h-5 opacity-70 group-hover:translate-x-1 transition-transform" />}
                </button>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default DialogueBox;

/**
 * GAME_CONFIG
 * 게임의 일반적인 규칙과 에너지 소모량을 정의합니다.
 * 주요 액션(수리, 상점 오픈, 제작) 시 소모되는 플레이어 자원량을 관리합니다.
 */
export const GAME_CONFIG = {
    ENERGY_COST: {
        REPAIR: 15,     // 대장간 수리 액션 시 소모 에너지
        OPEN_SHOP: 0,   // 상점 운영 시작 시 소모 에너지 (소모 없음으로 변경)
        CRAFT: 20       // 아이템 제작 시 소모 에너지
    }
};

import { GameState } from '../../types/index';
import { ShopCustomer } from '../../types/shop';
import { GAME_CONFIG } from '../../config/game-config';

export const handleToggleShop = (state: GameState): GameState => {
    const willOpen = !state.forge.isShopOpen;

    // 에너지 소모 로직 제거: 누구나 언제든 상점을 열고 닫을 수 있음
    return {
        ...state,
        forge: { ...state.forge, isShopOpen: willOpen },
        activeCustomer: willOpen ? state.activeCustomer : null,
        shopQueue: willOpen ? state.shopQueue : [],
        logs: [willOpen ? 'Shop is now OPEN.' : 'Shop is now CLOSED.', ...state.logs]
    };
};

export const handleEnqueueCustomer = (state: GameState, customer: ShopCustomer): GameState => {
    return {
        ...state,
        shopQueue: [...state.shopQueue, customer],
        visitorsToday: [...state.visitorsToday, customer.mercenary.id], 
        logs: [`${customer.mercenary.name} has entered the shop.`, ...state.logs]
    };
};

export const handleNextCustomer = (state: GameState): GameState => {
    if (state.shopQueue.length === 0) return state;
    const [next, ...remaining] = state.shopQueue;
    return { ...state, shopQueue: remaining, activeCustomer: next };
};

export const handleDismissCustomer = (state: GameState): GameState => {
    const logEntry = state.activeCustomer ? [`${state.activeCustomer.mercenary.name} left the shop.`] : [];
    return {
        ...state,
        activeCustomer: null,
        logs: [...logEntry, ...state.logs]
    };
};

export const handleRefuseCustomer = (state: GameState, payload: { mercenaryId: string; affinityLoss: number }): GameState => {
    const { mercenaryId, affinityLoss } = payload;

    let newKnownMercenaries = [...state.knownMercenaries];
    let newActiveCustomer = state.activeCustomer;

    const mercIdx = newKnownMercenaries.findIndex(m => m.id === mercenaryId);
    if (mercIdx > -1) {
        const merc = { ...newKnownMercenaries[mercIdx] };
        merc.affinity = Math.max(0, (merc.affinity || 0) - affinityLoss);
        newKnownMercenaries[mercIdx] = merc;

        // Sync to active customer for HUD
        if (newActiveCustomer && newActiveCustomer.mercenary.id === mercenaryId) {
            newActiveCustomer = {
                ...newActiveCustomer,
                mercenary: merc
            };
        }
    }

    const logMessage = affinityLoss > 0 
        ? `${newKnownMercenaries[mercIdx]?.name} was disappointed. Affinity dropped by ${affinityLoss}.`
        : `${newKnownMercenaries[mercIdx]?.name} accepted the refusal politely.`;

    return {
        ...state,
        knownMercenaries: newKnownMercenaries,
        activeCustomer: newActiveCustomer,
        logs: [logMessage, ...state.logs]
    };
};

import React, { createContext, useContext, useReducer, useMemo, useEffect, useRef } from 'react';
import { GameContextType, GameState } from '../types/index';
import { gameReducer } from '../state/gameReducer';
import { createInitialGameState } from '../state/initial-game-state';
import { EquipmentItem, EquipmentSlotType } from '../types/inventory';
import { ShopCustomer } from '../types/shop';
import { Mercenary } from '../models/Mercenary';
import { PrimaryStats } from '../models/Stats';
import { GAME_CONFIG } from '../config/game-config';
import { getEnergyCost } from '../utils/craftingLogic';
import { GameEvent } from '../types/events';
import { saveToSlot } from '../utils/saveSystem';

const GameContext = createContext<GameContextType | undefined>(undefined);

export const useGame = () => {
  const context = useContext(GameContext);
  if (context === undefined) {
    throw new Error('useGame must be used within a GameProvider');
  }
  return context;
};

interface GameProviderProps {
    initialSlotIndex?: number;
    children: React.ReactNode;
}

export const GameProvider: React.FC<GameProviderProps> = ({ children, initialSlotIndex = 0 }) => {
  const [state, dispatch] = useReducer(gameReducer, undefined, createInitialGameState);

  const currentSlotRef = useRef(initialSlotIndex);
  const stateRef = useRef(state);
  useEffect(() => { stateRef.current = state; }, [state]);

  const prevDayRef = useRef(state.stats.day);
  useEffect(() => {
    if (state.stats.day === prevDayRef.current + 1) {
      saveToSlot(currentSlotRef.current, state);
    }
    prevDayRef.current = state.stats.day;
  }, [state.stats.day, state]);

  // Debug: Tutorial Step Logging
  useEffect(() => {
      const scene = state.activeTutorialScene || 'NONE';
      const step = state.tutorialStep || 'NONE (Active Gameplay)';
      console.log(
          `%c[Tutorial Tracker] Scene: ${scene} | Step: ${step}`, 
          'color: #fbbf24; font-weight: bold; background: #1c1917; padding: 2px 6px; border-radius: 4px; border: 1px solid #fbbf24;'
      );
  }, [state.activeTutorialScene, state.tutorialStep]);

  useEffect(() => {
      if (!state.toast?.visible && state.toastQueue.length > 0) {
          const processTimer = setTimeout(() => {
              dispatch({ type: 'POP_NEXT_TOAST' });
          }, 150);
          return () => clearTimeout(processTimer);
      }
      if (state.toast?.visible) {
          const hideTimer = setTimeout(() => {
              dispatch({ type: 'HIDE_TOAST' });
          }, 3000);
          return () => clearTimeout(hideTimer);
      }
  }, [state.toast?.visible, state.toastQueue.length]);

  const triggerEnergyHighlight = () => {
      dispatch({ type: 'SET_UI_EFFECT', payload: { effect: 'energyHighlight', value: true } });
      setTimeout(() => {
          dispatch({ type: 'SET_UI_EFFECT', payload: { effect: 'energyHighlight', value: false } });
      }, 3000);
  };

  const showToast = (message: string) => {
      dispatch({ type: 'SHOW_TOAST', payload: message });
  };

  const actions = useMemo(() => ({
    repairItem: () => {
        if (stateRef.current.stats.energy < GAME_CONFIG.ENERGY_COST.REPAIR) { triggerEnergyHighlight(); return; }
        dispatch({ type: 'REPAIR_WORK' });
    },
    rest: () => dispatch({ type: 'SLEEP' }),
    confirmSleep: () => dispatch({ type: 'CONFIRM_SLEEP' }),
    closeRest: () => dispatch({ type: 'CLOSE_SLEEP_MODAL' }),
    triggerEvent: (event: GameEvent) => dispatch({ type: 'TRIGGER_EVENT', payload: event }),
    handleEventOption: (action: () => void) => { action(); dispatch({ type: 'CLOSE_EVENT' }); },
    closeEvent: () => dispatch({ type: 'CLOSE_EVENT' }),
    saveGame: (slotIndex?: number) => {
        const targetSlot = slotIndex !== undefined ? slotIndex : currentSlotRef.current;
        const success = saveToSlot(targetSlot, stateRef.current);
        if (success) { currentSlotRef.current = targetSlot; showToast(`Progress saved to Slot ${targetSlot + 1}.`); }
    },
    loadGame: (loadedState: GameState) => dispatch({ type: 'LOAD_GAME', payload: loadedState }),
    startCrafting: (item: EquipmentItem) => {
        const masteryCount = stateRef.current.craftingMastery[item.id] || 0;
        const energyCost = getEnergyCost(item, masteryCount);
        if (stateRef.current.stats.energy < energyCost) { triggerEnergyHighlight(); return; }
        dispatch({ type: 'START_CRAFTING', payload: { item } });
    },
    cancelCrafting: (item: EquipmentItem) => dispatch({ type: 'CANCEL_CRAFTING', payload: { item } }),
    finishCrafting: (item: EquipmentItem, quality: number, bonus?: number, masteryGain?: number) => dispatch({ type: 'FINISH_CRAFTING', payload: { item, quality, bonus, masteryGain } }),
    craftItem: (item: EquipmentItem, quality: number) => dispatch({ type: 'FINISH_CRAFTING', payload: { item, quality } }),
    dismissCraftingResult: () => dispatch({ type: 'DISMISS_CRAFTING_RESULT' }),
    dismissTierUnlock: () => dispatch({ type: 'DISMISS_TIER_UNLOCK' }),
    buyItems: (items: { id: string; count: number }[], totalCost: number) => dispatch({ type: 'BUY_MARKET_ITEMS', payload: { items, totalCost } }),
    sellItem: (itemId: string, count: number, price: number, equipmentInstanceId?: string, customer?: Mercenary) =>
        dispatch({ type: 'SELL_ITEM', payload: { itemId, count, price, equipmentInstanceId, customer } }),
    toggleShop: () => {
        // 에너지 소모가 0이므로 체크 로직 제거
        dispatch({ type: 'TOGGLE_SHOP' });
    },
    addMercenary: (merc: Mercenary) => dispatch({ type: 'ADD_KNOWN_MERCENARY', payload: merc }),
    scoutMercenary: (merc: Mercenary, cost: number) => dispatch({ type: 'SCOUT_MERCENARY', payload: { mercenary: merc, cost } }),
    consumeItem: (id: string, count: number) => dispatch({ type: 'PAY_COST', payload: { items: [{ id, count }] } }),
    enqueueCustomer: (customer: ShopCustomer) => dispatch({ type: 'ENQUEUE_CUSTOMER', payload: customer }),
    nextCustomer: () => dispatch({ type: 'NEXT_CUSTOMER' }),
    dismissCustomer: () => dispatch({ type: 'DISMISS_CUSTOMER' }),
    refuseCustomer: (mercenaryId: string, affinityLoss: number) => dispatch({ type: 'REFUSE_CUSTOMER', payload: { mercenaryId, affinityLoss } }),
    setCrafting: (isCrafting: boolean) => dispatch({ type: 'SET_CRAFTING', payload: isCrafting }),
    setResearchOpen: (isOpen: boolean) => dispatch({ type: 'SET_RESEARCH_OPEN', payload: isOpen }),
    updateForgeStatus: (temp: number) => dispatch({ type: 'UPDATE_FORGE_STATUS', payload: { temp } }),
    updateMercenaryStats: (mercenaryId: string, stats: PrimaryStats) => dispatch({ type: 'UPDATE_MERCENARY_STATS', payload: { mercenaryId, stats } }),
    toggleJournal: () => dispatch({ type: 'TOGGLE_JOURNAL' }),
    hireMercenary: (mercenaryId: string, cost: number) => dispatch({ type: 'HIRE_MERCENARY', payload: { mercenaryId, cost } }),
    fireMercenary: (mercenaryId: string) => dispatch({ type: 'FIRE_MERCENARY', payload: { mercenaryId } }),
    giveGift: (mercenaryId: string, itemId: string) => dispatch({ type: 'GIVE_GIFT', payload: { mercenaryId, itemId } }),
    talkMercenary: (mercenaryId: string) => dispatch({ type: 'TALK_MERCENARY', payload: { mercenaryId } }),
    talkGarrick: () => dispatch({ type: 'TALK_GARRICK' }),
    giftGarrick: (payload: { itemId: string }) => dispatch({ type: 'GIFT_GARRICK', payload }),
    researchCombination: (items: { id: string; count: number }[]) => dispatch({ type: 'RESEARCH_COMBINATION', payload: { items } }),
    startExpedition: (dungeonId: string, partyIds: string[]) => dispatch({ type: 'START_EXPEDITION', payload: { dungeonId, partyIds } }),
    completeExpedition: (expeditionId: string) => dispatch({ type: 'COMPLETE_EXPEDITION', payload: { expeditionId } }),
    abortExpedition: (expeditionId: string) => dispatch({ type: 'ABORT_EXPEDITION', payload: { expeditionId } }),
    claimExpedition: (expeditionId: string) => dispatch({ type: 'CLAIM_EXPEDITION', payload: { expeditionId } }),
    dismissDungeonResult: () => dispatch({ type: 'DISMISS_DUNGEON_RESULT' }),
    equipItem: (mercenaryId: string, inventoryItemId: string) => dispatch({ type: 'EQUIP_ITEM', payload: { mercenaryId, inventoryItemId } }),
    unequipItem: (mercenaryId: string, slot: EquipmentSlotType) => dispatch({ type: 'UNEQUIP_ITEM', payload: { mercenaryId, slot } }),
    useItem: (itemId: string, mercenaryId?: string) => dispatch({ type: 'USE_ITEM', payload: { itemId, mercenaryId } }),
    toggleLockItem: (itemId: string) => dispatch({ type: 'TOGGLE_LOCK_ITEM', payload: { itemId } }),
    allocateStat: (mercenaryId: string, stat: keyof PrimaryStats) => dispatch({ type: 'ALLOCATE_STAT', payload: { mercenaryId, stat } }),
    startManualAssault: (dungeonId: string, partyIds: string[], startFloor?: number) => 
        dispatch({ type: 'START_MANUAL_DUNGEON', payload: { dungeonId, partyIds, startFloor } }),
    moveInManualDungeon: (dx: number, dy: number) => 
        dispatch({ type: 'MOVE_MANUAL_DUNGEON', payload: { x: dx, y: dy } }),
    finishManualAssault: () => dispatch({ type: 'FINISH_MANUAL_DUNGEON' }),
    retreatFromManualDungeon: () => dispatch({ type: 'RETREAT_MANUAL_DUNGEON' }),
    toggleManualDungeonOverlay: (show: boolean) => dispatch({ type: 'TOGGLE_MANUAL_DUNGEON_OVERLAY', payload: show }),
    rescueMercenary: (npcId: string) => dispatch({ type: 'RESCUE_NPC', payload: { npcId } }),
    startCombatManual: () => dispatch({ type: 'START_COMBAT_MANUAL' }),
    resolveCombatManual: (win: boolean, flee: boolean, finalParty: any[]) => 
        dispatch({ type: 'RESOLVE_COMBAT_MANUAL', payload: { win, flee, finalParty } }),
    proceedToNextFloorManual: () => dispatch({ type: 'PROCEED_TO_NEXT_FLOOR_MANUAL' }),
    triggerEnergyHighlight,
    showToast,
    hideToast: () => dispatch({ type: 'HIDE_TOAST' }),
    setTutorialStep: (step: GameState['tutorialStep']) => dispatch({ type: 'SET_TUTORIAL_STEP', payload: step }),
    setTutorialScene: (mode: GameState['activeTutorialScene']) => dispatch({ type: 'SET_ACTIVE_TUTORIAL_SCENE', payload: mode }),
    completePrologue: () => dispatch({ type: 'COMPLETE_PROLOGUE' }),
    completeTutorial: () => dispatch({ type: 'COMPLETE_TUTORIAL' }),
    dismissTutorialComplete: () => dispatch({ type: 'DISMISS_TUTORIAL_COMPLETE' }),
    updateSettings: (settings: Partial<GameState['settings']>) => dispatch({ type: 'UPDATE_SETTINGS', payload: settings }),
  }), [dispatch]); 

  return (
    <GameContext.Provider value={{ state, actions }}>
      {children}
    </GameContext.Provider>
  );
};

